   603→                        </ul>
   604→                        <button class="card-btn" onclick="window.open('https://wa.me/5514997662250?text=Quero%20registrar%20minha%20marca', '_blank')">Saiba Mais</button>
   605→                    </div>
   606→                </div>
   607→
   608→                <!-- CARD 2 -->
