   631→                            <li>Monitoramento contínuo</li>
   632→                            <li>Ação contra falsificação</li>
   633→                            <li>Consultoria jurídica</li>
   634→                            <li>Recuperação de direitos</li>
   635→                        </ul>
   636→                        <button class="card-btn" onclick="window.open('https://wa.me/5514997662250?text=Preciso%20de%20proteção%20jurídica%20para%20minha%20marca', '_blank')">Saiba Mais</button>
   637→                    </div>
   638→                </div>
   639→
   640→                <!-- CARD 4 -->
   641→                <div class="card">
   642→                    <div class="card-header">🔍</div>
