/**
 * MATRE MARCAS - DESIGN SYSTEM
 * Sistema de Design Base para todas as páginas e serviços
 * Estilo: Apple + High Ticket + Autoridade
 * Versão: 1.0
 * Data: 2026-03-02
 */

/* ===== IMPORTAR GOOGLE FONTS ===== */
@import url('https://fonts.googleapis.com/css2?family=Inter:wght@300;400;500;600;700&display=swap');

/* ===== CSS CUSTOM PROPERTIES (DESIGN TOKENS) ===== */
:root {
    /* Cores */
    --color-dark: #0A0A0A;
    --color-navy: #001f3f;
    --color-accent: #C2185B;
    --color-accent-hover: #A71E52;
    --color-white: #FFFFFF;
    --color-surface: #F5F5F7;
    --color-text: #1D1D1F;
    --color-muted: #6E6E73;
    --color-border: #e0e0e0;
    --color-border-light: rgba(0, 0, 0, 0.05);
    --color-border-lighter: rgba(255, 255, 255, 0.1);

    /* Tipografia */
    --font-main: 'Inter', sans-serif;
    --font-size-xs: 12px;
    --font-size-sm: 14px;
    --font-size-base: 16px;
    --font-size-lg: 18px;
    --font-size-xl: 20px;
    --font-size-2xl: 28px;
    --font-size-3xl: 48px;
    --font-size-4xl: 64px;

    --font-weight-light: 300;
    --font-weight-normal: 400;
    --font-weight-medium: 500;
    --font-weight-semibold: 600;
    --font-weight-bold: 700;

    /* Espaçamento */
    --spacing-xs: 8px;
    --spacing-sm: 12px;
    --spacing-md: 16px;
    --spacing-lg: 24px;
    --spacing-xl: 32px;
    --spacing-2xl: 48px;
    --spacing-3xl: 60px;
    --spacing-4xl: 80px;
    --spacing-5xl: 120px;
    --spacing-6xl: 180px;

    /* Border Radius */
    --radius-sm: 6px;
    --radius-md: 12px;
    --radius-lg: 20px;
    --radius-full: 9999px;

    /* Shadows */
    --shadow-xs: 0 1px 2px rgba(0, 0, 0, 0.05);
    --shadow-sm: 0 2px 8px rgba(0, 0, 0, 0.05);
    --shadow-card: 0 2px 20px rgba(0, 0, 0, 0.08), 0 0 0 1px rgba(0, 0, 0, 0.04);
    --shadow-hover: 0 8px 40px rgba(0, 0, 0, 0.12), 0 0 0 1px rgba(0, 0, 0, 0.06);
    --shadow-glass: 0 8px 32px rgba(31, 38, 135, 0.37);

    /* Transições */
    --transition-fast: all 0.15s cubic-bezier(0.4, 0, 0.2, 1);
    --transition-smooth: all 0.3s cubic-bezier(0.4, 0, 0.2, 1);
    --transition-slow: all 0.5s cubic-bezier(0.4, 0, 0.2, 1);

    /* Line Height */
    --line-height-tight: 1.1;
    --line-height-normal: 1.6;
    --line-height-relaxed: 1.8;

    /* Letter Spacing */
    --letter-spacing-tight: -0.03em;
    --letter-spacing-normal: 0;
    --letter-spacing-wide: 0.12em;
}

/* ===== RESET & BASE ===== */
* {
    margin: 0;
    padding: 0;
    box-sizing: border-box;
}

html {
    scroll-behavior: smooth;
}

body {
    font-family: var(--font-main);
    color: var(--color-text);
    line-height: var(--line-height-normal);
    background: var(--color-white);
    font-size: var(--font-size-base);
    font-weight: var(--font-weight-normal);
    -webkit-font-smoothing: antialiased;
    -moz-osx-font-smoothing: grayscale;
}

/* ===== LAYOUT ===== */
.container {
    max-width: 1200px;
    margin: 0 auto;
    padding: 0 var(--spacing-md);
}

.container-sm {
    max-width: 800px;
    margin: 0 auto;
    padding: 0 var(--spacing-md);
}

.container-lg {
    max-width: 1400px;
    margin: 0 auto;
    padding: 0 var(--spacing-md);
}

/* ===== TIPOGRAFIA BASE ===== */
h1 {
    font-size: var(--font-size-4xl);
    font-weight: var(--font-weight-bold);
    letter-spacing: var(--letter-spacing-tight);
    line-height: var(--line-height-tight);
}

h2 {
    font-size: var(--font-size-3xl);
    font-weight: var(--font-weight-bold);
    letter-spacing: var(--letter-spacing-tight);
    line-height: var(--line-height-tight);
}

h3 {
    font-size: var(--font-size-2xl);
    font-weight: var(--font-weight-bold);
    letter-spacing: var(--letter-spacing-tight);
    line-height: var(--line-height-tight);
}

h4 {
    font-size: var(--font-size-xl);
    font-weight: var(--font-weight-semibold);
    letter-spacing: var(--letter-spacing-tight);
    line-height: var(--line-height-tight);
}

p {
    font-weight: var(--font-weight-normal);
    line-height: var(--line-height-normal);
}

small {
    font-size: var(--font-size-sm);
    font-weight: var(--font-weight-normal);
}

strong {
    font-weight: var(--font-weight-semibold);
}

/* ===== BOTÕES ===== */
button,
.btn {
    font-family: inherit;
    font-size: inherit;
    border: none;
    cursor: pointer;
    transition: var(--transition-smooth);
    border-radius: var(--radius-md);
    font-weight: var(--font-weight-semibold);
}

.btn-primary {
    background: var(--color-accent);
    color: var(--color-white);
    padding: var(--spacing-md) var(--spacing-lg);
}

.btn-primary:hover {
    background: var(--color-accent-hover);
    transform: translateY(-2px);
    box-shadow: 0 4px 16px rgba(194, 24, 91, 0.3);
}

.btn-secondary {
    background: transparent;
    color: var(--color-navy);
    border: 1.5px solid var(--color-navy);
    padding: var(--spacing-md) var(--spacing-lg);
}

.btn-secondary:hover {
    background: var(--color-navy);
    color: var(--color-white);
}

.btn-outline-white {
    background: transparent;
    color: var(--color-white);
    border: 1.5px solid var(--color-white);
    padding: var(--spacing-md) var(--spacing-lg);
}

.btn-outline-white:hover {
    background: var(--color-white);
    color: var(--color-dark);
    transform: translateY(-2px);
}

.btn-small {
    padding: var(--spacing-sm) var(--spacing-md);
    font-size: var(--font-size-sm);
}

.btn-large {
    padding: var(--spacing-lg) var(--spacing-xl);
    font-size: var(--font-size-lg);
}

.btn-full {
    width: 100%;
}

/* ===== CARDS ===== */
.card {
    background: var(--color-white);
    border: 1px solid var(--color-border);
    border-radius: var(--radius-md);
    overflow: hidden;
    box-shadow: var(--shadow-card);
    transition: var(--transition-smooth);
}

.card:hover {
    transform: translateY(-4px);
    box-shadow: var(--shadow-hover);
    border-color: var(--color-accent);
}

.card-header {
    background: var(--color-surface);
    padding: var(--spacing-xl);
    border-bottom: 1px solid var(--color-border);
    display: flex;
    align-items: center;
    justify-content: center;
    min-height: 100px;
}

.card-content {
    padding: var(--spacing-xl);
}

.card-footer {
    padding: var(--spacing-lg) var(--spacing-xl);
    border-top: 1px solid var(--color-border);
    background: var(--color-surface);
}

/* ===== BADGES ===== */
.badge {
    display: inline-block;
    padding: var(--spacing-sm) var(--spacing-md);
    border-radius: var(--radius-full);
    font-size: var(--font-size-xs);
    font-weight: var(--font-weight-semibold);
    letter-spacing: var(--letter-spacing-wide);
    text-transform: uppercase;
}

.badge-primary {
    background: rgba(194, 24, 91, 0.15);
    color: var(--color-accent);
    border: 1px solid rgba(194, 24, 91, 0.3);
}

.badge-neutral {
    background: var(--color-surface);
    color: var(--color-text);
    border: 1px solid var(--color-border);
}

/* ===== FORMULÁRIOS ===== */
input,
textarea,
select {
    font-family: inherit;
    font-size: inherit;
    padding: var(--spacing-md);
    border: 1.5px solid var(--color-border);
    border-radius: var(--radius-md);
    background: var(--color-white);
    color: var(--color-text);
    transition: var(--transition-smooth);
}

input:focus,
textarea:focus,
select:focus {
    outline: none;
    border-color: var(--color-accent);
    box-shadow: 0 0 0 3px rgba(194, 24, 91, 0.1);
}

input::placeholder,
textarea::placeholder {
    color: var(--color-muted);
}

/* ===== LISTAS ===== */
.list-clean {
    list-style: none;
}

.list-clean li {
    padding: var(--spacing-md) 0;
    display: flex;
    align-items: center;
    gap: var(--spacing-md);
}

.list-clean li:before {
    content: "✓";
    color: var(--color-accent);
    font-weight: var(--font-weight-bold);
    font-size: var(--font-size-lg);
    flex-shrink: 0;
}

/* ===== GRID ===== */
.grid {
    display: grid;
    gap: var(--spacing-lg);
}

.grid-2 {
    grid-template-columns: repeat(2, 1fr);
}

.grid-3 {
    grid-template-columns: repeat(3, 1fr);
}

.grid-4 {
    grid-template-columns: repeat(4, 1fr);
}

@media (max-width: 1024px) {
    .grid-4 {
        grid-template-columns: repeat(2, 1fr);
    }

    .grid-3 {
        grid-template-columns: repeat(2, 1fr);
    }
}

@media (max-width: 768px) {
    .grid-2,
    .grid-3,
    .grid-4 {
        grid-template-columns: 1fr;
    }
}

/* ===== FLEX ===== */
.flex {
    display: flex;
}

.flex-between {
    display: flex;
    justify-content: space-between;
    align-items: center;
}

.flex-center {
    display: flex;
    justify-content: center;
    align-items: center;
}

.flex-col {
    flex-direction: column;
}

.gap-xs {
    gap: var(--spacing-xs);
}

.gap-sm {
    gap: var(--spacing-sm);
}

.gap-md {
    gap: var(--spacing-md);
}

.gap-lg {
    gap: var(--spacing-lg);
}

.gap-xl {
    gap: var(--spacing-xl);
}

/* ===== SPACING ===== */
.p-xs {
    padding: var(--spacing-xs);
}

.p-sm {
    padding: var(--spacing-sm);
}

.p-md {
    padding: var(--spacing-md);
}

.p-lg {
    padding: var(--spacing-lg);
}

.p-xl {
    padding: var(--spacing-xl);
}

.m-xs {
    margin: var(--spacing-xs);
}

.m-sm {
    margin: var(--spacing-sm);
}

.m-md {
    margin: var(--spacing-md);
}

.m-lg {
    margin: var(--spacing-lg);
}

.m-xl {
    margin: var(--spacing-xl);
}

.py-3xl {
    padding-top: var(--spacing-3xl);
    padding-bottom: var(--spacing-3xl);
}

.py-4xl {
    padding-top: var(--spacing-4xl);
    padding-bottom: var(--spacing-4xl);
}

.py-5xl {
    padding-top: var(--spacing-5xl);
    padding-bottom: var(--spacing-5xl);
}

.py-6xl {
    padding-top: var(--spacing-6xl);
    padding-bottom: var(--spacing-6xl);
}

/* ===== BACKGROUNDS ===== */
.bg-dark {
    background: var(--color-dark);
    color: var(--color-white);
}

.bg-navy {
    background: var(--color-navy);
    color: var(--color-white);
}

.bg-surface {
    background: var(--color-surface);
    color: var(--color-text);
}

.bg-white {
    background: var(--color-white);
    color: var(--color-text);
}

/* ===== TEXT UTILITIES ===== */
.text-center {
    text-align: center;
}

.text-left {
    text-align: left;
}

.text-right {
    text-align: right;
}

.text-muted {
    color: var(--color-muted);
}

.text-accent {
    color: var(--color-accent);
}

.text-white {
    color: var(--color-white);
}

.text-sm {
    font-size: var(--font-size-sm);
}

.text-lg {
    font-size: var(--font-size-lg);
}

.font-bold {
    font-weight: var(--font-weight-bold);
}

.font-semibold {
    font-weight: var(--font-weight-semibold);
}

.font-light {
    font-weight: var(--font-weight-light);
}

.uppercase {
    text-transform: uppercase;
    letter-spacing: var(--letter-spacing-wide);
}

/* ===== ANIMAÇÕES ===== */
.fade-in {
    opacity: 0;
    transform: translateY(20px);
    transition: var(--transition-smooth);
}

.fade-in.visible {
    opacity: 1;
    transform: translateY(0);
}

.slide-in-left {
    opacity: 0;
    transform: translateX(-20px);
    transition: var(--transition-smooth);
}

.slide-in-left.visible {
    opacity: 1;
    transform: translateX(0);
}

.slide-in-right {
    opacity: 0;
    transform: translateX(20px);
    transition: var(--transition-smooth);
}

.slide-in-right.visible {
    opacity: 1;
    transform: translateX(0);
}

/* ===== RESPONSIVO MOBILE ===== */
@media (max-width: 768px) {
    h1 {
        font-size: var(--font-size-3xl);
    }

    h2 {
        font-size: var(--font-size-2xl);
    }

    h3 {
        font-size: var(--font-size-xl);
    }

    .container {
        padding: 0 var(--spacing-md);
    }

    .py-6xl {
        padding-top: var(--spacing-5xl);
        padding-bottom: var(--spacing-5xl);
    }

    .py-5xl {
        padding-top: var(--spacing-4xl);
        padding-bottom: var(--spacing-4xl);
    }
}

/* ===== UTILITÁRIOS ===== */
.hidden {
    display: none;
}

.invisible {
    visibility: hidden;
}

.opacity-50 {
    opacity: 0.5;
}

.opacity-75 {
    opacity: 0.75;
}

.rounded {
    border-radius: var(--radius-md);
}

.shadow {
    box-shadow: var(--shadow-card);
}

.shadow-lg {
    box-shadow: var(--shadow-hover);
}

.transition {
    transition: var(--transition-smooth);
}

