        const header = document.querySelector(headerSelector);
        if (!header) return;

        window.addEventListener('scroll', () => {
            if (window.scrollY > threshold) {
                header.classList.add('scrolled');
            } else {
                header.classList.remove('scrolled');
            }
        });
    },

    /**
     * Fecha menu mobile ao clicar em um link
     * @param {string} navSelector - Seletor da nav (padrão: 'nav')
     * @param {string} toggleSelector - Seletor do botão toggle (padrão: '.nav-toggle')
     */
    initMobileMenuClose(navSelector = 'nav', toggleSelector = '.nav-toggle') {
        const navLinks = document.querySelectorAll(`${navSelector} a`);
        const toggle = document.querySelector(toggleSelector);

        navLinks.forEach(link => {
            link.addEventListener('click', () => {
                if (toggle && toggle.classList.contains('active')) {
                    toggle.classList.remove('active');
                    document.querySelector(navSelector).classList.remove('active');
                }
            });
        });
    }
};

// ===== INTERSECTION OBSERVER UTILITIES =====
const MatreObserver = {
    /**
     * Ativa animações fade-in em elementos
     * @param {string} selector - Seletor dos elementos (padrão: '.fade-in')
     * @param {object} options - Opções do IntersectionObserver
     */
    initFadeIn(selector = '.fade-in', options = {}) {
        const defaultOptions = {
            threshold: 0.1,
            rootMargin: '0px 0px -50px 0px'
        };

        const observerOptions = { ...defaultOptions, ...options };
        const observer = new IntersectionObserver((entries) => {
            entries.forEach(entry => {
                if (entry.isIntersecting) {
                    entry.target.classList.add('visible');
                    observer.unobserve(entry.target);
                }
            });
        }, observerOptions);

        document.querySelectorAll(selector).forEach(element => {
            observer.observe(element);
        });

        return observer;
    },

    /**
     * Ativa múltiplos observadores com classes diferentes
     * @param {object} config - { selector: options }
     */
    initMultiple(config = {}) {
        const defaults = {
            '.fade-in': { threshold: 0.1, rootMargin: '0px 0px -50px 0px' },
            '.slide-in-left': { threshold: 0.1, rootMargin: '0px 0px -50px 0px' },
            '.slide-in-right': { threshold: 0.1, rootMargin: '0px 0px -50px 0px' }
        };

        const finalConfig = { ...defaults, ...config };

        Object.entries(finalConfig).forEach(([selector, options]) => {
            this.initFadeIn(selector, options);
        });
    }
};

// ===== FORM UTILITIES =====
const MatreForm = {
    /**
     * Inicializa formulário com feedback visual
     * @param {string} formSelector - Seletor do formulário
     * @param {string} feedbackSelector - Seletor do elemento de feedback
     * @param {function} onSubmit - Callback custom (opcional)
     */
    initForm(formSelector, feedbackSelector, onSubmit = null) {
        const form = document.querySelector(formSelector);
        const feedback = document.querySelector(feedbackSelector);

        if (!form) return;

        form.addEventListener('submit', (e) => {
            e.preventDefault();

            if (onSubmit) {
                onSubmit(form, feedback);
            } else {
                this.defaultFormHandler(form, feedback);
            }
        });
    },

    /**
     * Handler padrão de formulário
     * @param {HTMLElement} form - Elemento do formulário
     * @param {HTMLElement} feedback - Elemento de feedback
     */
    defaultFormHandler(form, feedback) {
        const inputs = form.querySelectorAll('input[required], textarea[required]');
        let isValid = true;

        inputs.forEach(input => {
            if (!input.value.trim()) {
                isValid = false;
            }
        });

        if (!isValid) {
            this.showFeedback(feedback, 'Por favor, preencha todos os campos.', 'error');
            return;
        }

        this.showFeedback(
            feedback,
            '✓ Suas informações foram recebidas! Entraremos em contato em breve.',
            'success'
        );

        form.reset();

        setTimeout(() => {
            feedback.classList.remove('success', 'error');
        }, 5000);
    },

    /**
     * Mostra mensagem de feedback
     * @param {HTMLElement} element - Elemento de feedback
     * @param {string} message - Mensagem
     * @param {string} type - Tipo: 'success' ou 'error'
     */
    showFeedback(element, message, type = 'success') {
        if (!element) return;

        element.textContent = message;
        element.classList.remove('success', 'error');
        element.classList.add(type);
    },

    /**
     * Valida email
     * @param {string} email - Email a validar
     * @returns {boolean}
     */
    validateEmail(email) {
        const regex = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;
        return regex.test(email);
    },

    /**
     * Valida campo obrigatório
     * @param {string} value - Valor a validar
     * @returns {boolean}
     */
    validateRequired(value) {
        return value.trim().length > 0;
    }
};

// ===== MODAL UTILITIES =====
const MatreModal = {
    /**
     * Abre modal
     * @param {string} modalSelector - Seletor do modal
     */
    open(modalSelector) {
        const modal = document.querySelector(modalSelector);
        if (modal) {
            modal.classList.add('active');
            document.body.style.overflow = 'hidden';
        }
    },

    /**
     * Fecha modal
     * @param {string} modalSelector - Seletor do modal
     */
    close(modalSelector) {
        const modal = document.querySelector(modalSelector);
        if (modal) {
            modal.classList.remove('active');
            document.body.style.overflow = 'auto';
        }
    },

    /**
     * Inicializa modal com triggers
     * @param {string} openSelector - Seletor do botão abrir
     * @param {string} closeSelector - Seletor do botão fechar
     * @param {string} modalSelector - Seletor do modal
     */
    init(openSelector, closeSelector, modalSelector) {
        document.querySelectorAll(openSelector).forEach(btn => {
            btn.addEventListener('click', () => this.open(modalSelector));
        });

        document.querySelectorAll(closeSelector).forEach(btn => {
            btn.addEventListener('click', () => this.close(modalSelector));
        });

        // Fechar ao clicar fora do modal
        document.querySelector(modalSelector)?.addEventListener('click', (e) => {
            if (e.target.classList.contains('modal')) {
                this.close(modalSelector);
            }
        });
    }
};

// ===== WHATSAPP UTILITIES =====
const MatreWhatsApp = {
    /**
     * Abre WhatsApp com mensagem customizada
     * @param {string} phone - Número com DDD (ex: 5514997662250)
     * @param {string} message - Mensagem (será URLencoded)
     */
    openChat(phone, message = '') {
        const encodedMessage = encodeURIComponent(message);
        const url = `https://wa.me/${phone}?text=${encodedMessage}`;
        window.open(url, '_blank');
    },

    /**
     * Inicializa botões WhatsApp
     * @param {string} selector - Seletor dos botões (padrão: '.whatsapp-btn')
     * @param {string} phone - Número padrão (padrão: 5514997662250)
     */
    initButtons(selector = '.whatsapp-btn', phone = '5514997662250') {
        document.querySelectorAll(selector).forEach(btn => {
            btn.addEventListener('click', () => {
                const message = btn.dataset.message || '';
                this.openChat(phone, message);
            });
        });
    }
};

// ===== THROTTLE & DEBOUNCE =====
const MatrePerformance = {
    /**
     * Throttle - Executa função no máximo a cada X ms
     * @param {function} func - Função a executar
     * @param {number} limit - Limit em ms
     * @returns {function}
     */
    throttle(func, limit = 100) {
        let inThrottle;
        return function(...args) {
            if (!inThrottle) {
                func.apply(this, args);
                inThrottle = true;
                setTimeout(() => (inThrottle = false), limit);
            }
        };
    },

    /**
     * Debounce - Executa função após X ms de inatividade
     * @param {function} func - Função a executar
     * @param {number} delay - Delay em ms
     * @returns {function}
     */
    debounce(func, delay = 300) {
        let timeoutId;
        return function(...args) {
            clearTimeout(timeoutId);
            timeoutId = setTimeout(() => func.apply(this, args), delay);
        };
    }
};

// ===== ANALYTICS & TRACKING =====
const MatreTracking = {
    /**
     * Rastreia clique em botão
     * @param {string} buttonName - Nome do botão
     * @param {object} data - Dados adicionais
     */
    trackButtonClick(buttonName, data = {}) {
        if (window.gtag) {
            gtag('event', 'button_click', {
                button_name: buttonName,
                ...data
            });
        }
        console.log(`[TRACKING] Button Click: ${buttonName}`, data);
    },

    /**
     * Rastreia submissão de formulário
     * @param {string} formName - Nome do formulário
     * @param {object} data - Dados adicionais
     */
    trackFormSubmit(formName, data = {}) {
        if (window.gtag) {
            gtag('event', 'form_submit', {
                form_name: formName,
                ...data
            });
        }
        console.log(`[TRACKING] Form Submit: ${formName}`, data);
    },

    /**
     * Rastreia link externo
     * @param {string} url - URL do link
     * @param {string} label - Label do link
     */
    trackOutboundLink(url, label = '') {
        if (window.gtag) {
            gtag('event', 'click', {
                event_category: 'outbound',
                event_label: label,
                value: url
            });
        }
        console.log(`[TRACKING] Outbound Link: ${url}`, label);
    }
};

